UPDATE survey_templates
SET is_default = false,
updated_at = CURRENT_TIMESTAMP
WHERE company_id = #{companyId}
AND stage = #{stage}
AND target_role = #{targetRole}
AND coalesce(purpose, 'ONBOARDING_FEEDBACK') = 'ONBOARDING_FEEDBACK'
AND is_default = true
AND survey_template_id <> #{excludeTemplateId}
